PRAGMA foreign_keys = ON;

-- Часть 2 из 28. Существующие тайтлы не перезаписываются.

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098965c","title":"Победители невозможного","author":"Алексей Волков","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002717042/140/0993/Aleksej_Volkov__Pobediteli_nevozmozhnogo.jpg","isbn":"978-5-9908125-9-8","publisher":"ИП Коташевская Б. Д.","pubDate":"2017","language":"Русский","series":"","genres":[],"annotation":"Победители Невозможного вдохновлены не только обширным пластом западных и российских комиксов, но и фантастикой (в том числе, советской), и классической литературой, и даже старым аниме. От Булгакова до Стругацких, от Metal Men до \"Приключений Электроника\", от Булычева до Dragon Ball Z - референсы и культурные аллюзии превращают сборник во что-то куда более важное, чем просто комикс о четверке людей с суперспособностями.  Это независимый проект команды, которая невероятно много делает для развития российской комикс-культуры. Те, кто читал \"Фронтир\", наверняка с нами согласятся - \"Победителей Невозможного\" без внимания оставить нельзя. - Это просто очень увлекательный комикс (кстати, авторы обещают продолжение!), и вкупе с подробной историей создания персонажей и отдельных сюжетов - она, разумеется, тоже включена в сборник - он создает мир альтернативной России, в которой (и из которой) герои ухитряются попадать в самые странные места и ситуации.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-06","rating":3.5,"review":"","added":9999964,"hdCover":""},{"id":"098965b","title":"Девочка-Апокалипсис. Ария конца света","author":"Эндрю Маклин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001863261/140/63f9/Endryu_Maklin__DevochkaApokalipsis._Ariya_kontsa_sveta.jpg","isbn":"978-5-9908127-1-0","publisher":"Jellyfish Jam","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Научно-фантастический комикс о пост-апокалиптической жизни и уходу за кошками!  Ария: она совсем одна на краю мира, но у нее есть задание! Ну не совсем одна – с ней её кот Драже. В заросших джунглями руинах города, они вместе ищут древний артефакт невероятной мощи. Когда она чуть не погибает после нападения дикарей, Ария вдруг выходит на след артефакта. Но она не единственная, кто охотится за ним – и теперь, чтобы выполнить задание и наконец вернуться домой, Арии придется взглянуть в лицо смерти.  «Девочка-Апокалипсис: Ария Конца света» - первый графический роман инди-сенсации Эндрю Маклина, мощное высказывание о природе жестокости и человечности на развалинах мира будущего.  «Эндрю Маклин – не просто один из моих любимых художников. Его «Девочка-Апокалипсис» так умело сочетает элементы «Навсикаи из Долины Ветров» и «Времени Приключений», что он теперь один из моих любимых авторов комиксов», - Майкл Эвон Оминг (создатель комикса «Powers»)  «Эндрю Маклин – один из самых оригинальных комиксистов. Он видит мир иначе, чем мы, и потому он просто идеален для этого медиума», - Джон Аркуди («Б.Р.П.Д», «Rumble»)","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-02","rating":3.5,"review":"","added":9999963,"hdCover":""},{"id":"098965a","title":"Война Зомби","author":"Кевин Истмен","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004688565/140/6722/Kevin_Istmen__Vojna_Zombi.jpg","isbn":"978-5-04-113213-2","publisher":"КомФедерация","pubDate":"2020","language":"Русский","series":"","genres":["Биографии и мемуары"],"annotation":"Такого зомби-апокалипсиса вы ещё не видели! На военных кладбищах мёртвые восстают из своих могил!  Кто остановит их?! Лётчице-истребителю Джине предстоит выяснить, что возвращает этих вооружённых до зубов мертвецов, и как их вновь отправить на тот свет. Ураганный зомби экшн, выполненный в лучших традициях фильмов категории \"Б\", от Кевина Истмана (\"Подростки Мутанты Ниндзя Черепашки\") и Эрика Тэлбота (Heavy Metal)!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4,"review":"","added":9999962,"hdCover":""},{"id":"0989659","title":"Годзилла в Аду","author":"Джеймс Стоко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003627594/140/535a/Dzhejms_Stoko__Godzilla_v_Adu.jpg","isbn":"","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Годзилла в Аду» — от автора и художника недавнего комикса «Годзилла: Полувековая война» Джеймса Стоко, а также других талантливых художников.  Король монстров попадает в Ад! А там его уже поджидают как инфернальные версии побеждённых им врагов, так и местные гигантские твари. С каждым выпуском Годзилла опускается на новый уровень Преисподней, и показывать кто тут главный кайдзю на районе становится всё сложнее!  Минисерия состоит из пяти выпусков. Издание подготовлено совместно с командой Vicious Membrane.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":2.5,"review":"","added":9999961,"hdCover":""},{"id":"0989658","title":"Годзилла: Полувековая война","author":"Джеймс Стоко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003403809/140/c4b8/Dzhejms_Stoko__Godzilla_Poluvekovaya_vojna.jpg","isbn":"978-5-04-104095-6","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ЭТО НОВЫЙ И ЗАХВАТЫВАЮЩИЙ ВЗГЛЯД НА ЦАРСТВО УНИЧТОЖЕНИЯ ГОДЗИЛЛЫ ОТ ДЖЕЙМСА СТОКО! В 1954-ом году лейтенант Ота Мураками оказывается свидетелем первого нападения Годзиллы на Японию. Вместе со своим товарищем Кентаро, Ота отчаянно старается спасти жизни… И в процессе этого его одержимость Королём Монстров растягивается на долгие 50 лет!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2025-01","rating":4,"review":"Предыдущее прочтение: Июнь 2021, оценка 4","added":9999960,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989657","title":"Зомби против роботов","author":"Эшли Вуд,Крис Райалл","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001271613/140/64ac/__Zombi_protiv_robotov.jpg","isbn":"978-5-91339-320-3","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Все началось с простой идеи – бездушные роботы борются с взбесившимися зомби за жизнь последнего живого человеческого ребенка. Когда в эту историю внезапно вмешиваются выжившие Амазонки, противостояние выливается в крупномасштабную битву, наполнившую весь мир гулом войны! Полное издание, включающее все комиксы серий «Зомби против Роботов» и «Зомби против Роботов против Амазонок».  Эшли Вуд – австралийский художник и иллюстратор, известный своим уникальным стилем, совмещающим масляную живопись и цифровые технологии. Этот микс превращает каждый его комикс в произведение искусства.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4.5,"review":"","added":9999959,"hdCover":""},{"id":"0989656","title":"Я убил Адольфа Гитлера","author":"Джейсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001590602/140/ebbb/Dzhejson__Ya_ubil_Adolfa_Gitlera.jpg","isbn":"978-5-91339-398-2","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ЧТО, ЕСЛИ БЫ мы жили в мире, где «наёмный убийца» — это законная и обычная профессия, как доктор или адвокат?  ЧТО, ЕСЛИ БЫ учёный нанял такого убийцу на самое потрясающее задание в его карьере… отправиться назад во времени и убить Адольфа Гитлера до того, как он стал злым диктатором?  А ЧТО, ЕСЛИ БЫ Гитлеру удалось пережить покушение, проникнуть в машину времени и попасть в XXI век… оставив будущего убийцу одного на 70 лет?  Если вы думаете, что знаете ответы на эти вопросы… то ошибаетесь. И вы обязательно должны прочитать «Я убил Адольфа Гитлера», шедевр с серьёзной миной от Джейсона.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4,"review":"","added":9999958,"hdCover":""},{"id":"0989655","title":"Бандитка. Вуаля!","author":"Пол Тобин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002777216/140/4ea2/Pol_Tobin__Banditka._Vualya.jpg","isbn":"978-5-6040823-0-0","publisher":"Jellyfish Jam","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Она загадочна, дерзка и неуловима. Она считает себя лучшей воровкой в мире и готова пойти наперекор властям и преступному миру. Она - Бандитка! Но сейчас она ввязалась в опасное дело, которое может стоить ей не только свободы, но и жизни. Сможет ли Бандитка справиться с угрозой, не потеряв стиля и присутствия духа?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4,"review":"","added":9999957,"hdCover":""},{"id":"0989654","title":"Дом Покаяния","author":"Питер Дж. Томаси","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007315605/140/6c89/Piter_Dzh._Tomasi__Dom_Pokayaniya.jpg","isbn":"978-5-6047218-3-4","publisher":"Alpaca","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"1905 год. Молодая вдова Сара Винчестер ведёт масштаб ную стройку: день и ночь не стихает бой молотков, а новые комнаты, этажи и ложные ходы появляются в её доме один за другим. Злые языки говорят, наследница оружейной империи выжила из ума. Но им невдомёк, что дом Сары – это пристанище заблудших душ. Никто не знает, что лишь звуки инструментов мешают призра кам невинных жертв отомстить Саре за грехи её семьи…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":3.5,"review":"","added":9999956,"hdCover":""},{"id":"0989653","title":"Кромвель Стоун. Полное издание (сборник)","author":"Андреас","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008837178/140/f7a4/Andreas__Kromvel_Stoun._Polnoe_izdanie_sbornik.jpg","isbn":"978-5-00116-904-8","publisher":"Питер","pubDate":"2023","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Трилогия Андреаса в духе лавкрафтовских ужасов впервые на русском языке.  Тринадцать человек чудом спасаются после бунта на корабле, но затем начинают один за другим исчезать при таинственных и зловещих обстоятельствах. Кромвель Стоун может стать следующим, поэтому он решает выяснить, кто стоит за этими похищениями, но оказывается втянут в гораздо более опасную и странную историю, чем мог себе представить.  Издание включает три части графического романа: \"Кромвель Стоун\", \"Возвращение Кромвеля Стоуна\" и \"Завещание Кромвеля Стоуна\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2025-01","rating":4.5,"review":"","added":9999955,"hdCover":""},{"id":"0989652","title":"Kingsman. Красный алмаз","author":"Роб Уильямс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005966154/140/102a/Rob_Uilyams__Kingsman._Krasnyj_almaz.jpg","isbn":"978-5-04-119109-2","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"Комиксы по фильмам, играм и сериалам","genres":["Комиксы","манга","графические романы"],"annotation":"Сиквел полюбившегося критикам комикса Марка Миллара и Дэйва Гиббонса \"Kingsman. Секретная служба\", набитый приключениями до отказа. Эггси вернулся. Ему приказано спасти принца Филиппа и раскрыть международный террористический заговор, а заодно доказать, что он — настоящий агент Kingsman... и спасти мир. Его дяди-наставника больше нет рядом, и Эггси придётся полагаться только на собственные шпионские навыки, чтобы выследить злодея, решившего уничтожить всю мировую экономику. По всему миру вспыхивают беспорядки, общество в современном его виде вот-вот погибнет, а Эггси отвлекает от задания невероятно сексуальная шпионка из Южной Африки...  Эта серия-бомба за авторством Роба Уильямса (\"Отряд самоубийц\") и Саймона Фрейзера расскажет о том, как наш герой из народа справляется с задачей, которая сделала бы честь самому Джеймсу Бонду.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2024-09","rating":3,"review":"","added":9999954,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989651","title":"Kingsman. Секретная служба","author":"Марк Миллар,Дэйв Гиббонс,Мэттью Вон,Энди Маннинг,Ангус Макки,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006077574/140/8a92/__Kingsman._Sekretnaya_sluzhba.jpg","isbn":"978-5-04-116450-8","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В 2014 году автор комикса \"Мордобой\" Марк Миллар, легендарный художник \"Хранителей\" Дэйв Гиббонс и популярный кинорежиссёр Мэтью Вон объединились в работе над одним из лучших новых комиксов последних лет \"Kingsman: Секретная служба\", чтобы в двадцать первом веке заново изобрести жанр шпионской драмы. Успех киноленты был закреплён спустя три года продолжением \"Kingsman: Золотое кольцо\", а в 2020 году зрителей ожидает и приквел оригинальной истории. Но всё началось с комикса, который вы держите в руках...  Агент британской секретной службы берётся перевоспитать своего непутёвого племянника после того, как тот в очередной раз попадает в полицейский участок. С целью наставить юношу на путь истинный дядя начинает обучать Гэри тонкостям своего ремесла, чтобы превратить парня из лондонского гопника в супершпиона! Долой спортивную одежду и дешёвые побрякушки, пришло время дорогих костюмов и пуленепробиваемых зонтиков. Теперь вместе они должны раскрыть таинственные похищения суперзвезд научно-фантастических фильмов и предотвратить уничтожение 90% населения Земли.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2024-09","rating":3.5,"review":"","added":9999953,"hdCover":""},{"id":"0989650","title":"Доктор Стрэндж. Клятва","author":"Брайан К. Вон,Маркос Мартин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001518880/140/864c/__Doktor_Strendzh._Klyatva.jpg","isbn":"ISSN 2304-9057","publisher":"Ашет Коллекция, Панини Рус","pubDate":"2016","language":"Русский","series":"Marvel. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"Доктор Стефан Стрэндж должен расследовать самое важное мистическое дело за всю его карьеру - попытку покушения на его собственную жизнь! Чтобы раскрыть эту тайну Стрэнджу придется совершить удивительное путешествие через параллельные реальности и преступный мир Нью-Йорка. Ситуация осложняется тем, что лучший друг Стрэнджа - его преданный ученик Вонг - находится на краю гибели.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2023-12","rating":4,"review":"","added":9999952,"hdCover":""},{"id":"098964f","title":"1602","author":"Нил Гейман,Энди Куберт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001437850/140/716f/__1602.jpg","isbn":"2304-9057","publisher":"Ашет Коллекция, Панини Рус","pubDate":"2015","language":"Русский","series":"Marvel. Официальная коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"Англия, 1602 год - Елизаветинская эпоха подходит к концу, страну будоражат странные грозы и слухи о могущественных потусторонних существах, которые бродят по земле. По всей Европе такие знакомые и вместе с тем такие совершенно новые герои и злодеи, включая Ника Фьюри, Человека-Паука, Людей Икс и Доктора Дума, оказываются впутанными в хитроумный заговор, который может приблизить конец света.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2023-12","rating":4,"review":"","added":9999951,"hdCover":""},{"id":"098964e","title":"I am a Hero, Volume 22","author":"Kengo Hanazawa","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002828296/140/06d4/Kengo_Hanazawa__I_am_a_Hero_Volume_22.jpg","isbn":"978-4091893796","publisher":"Shogakukan","pubDate":"2017","language":"Японский","series":"I am a Hero","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"s