  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989638","title":"Человек-бензопила. Книга 8. Спойлер","author":"Тацуки Фудзимото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008516427/140/4bc4/Tatsuki_Fudzimoto__Chelovekbenzopila._Kniga_8._Spojler.jpg","isbn":"978-5-389-23017-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2023","language":"Русский","series":"Графические романы. Манга","genres":["Комиксы","манга","графические романы"],"annotation":"Прежняя жизнь Асы Митаки осталась позади: еще вчера девушка была обычной школьницей, а уже сегодня — оказалась втянута в конфликт могущественных демонических существ. Теперь Аса делит тело с Йор, демоном-войной, и единственный способ избавиться от нежелательной попутчицы — помочь ей сразить Человека-Бензопилу. Но сделать это, судя по всему, будет не так-то просто... Тем временем Дэндзи продолжает беззаботно проводить время и наслаждаться возросшим вниманием к своему альтер эго, даже не зная, что над ним самим нависла смертельная опасность. В книгу вошел 13-й том манги (главы 104–112).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2023-03","rating":4.5,"review":"","added":9999928,"hdCover":""},{"id":"0989637","title":"Человек-бензопила. Книга 7. Птица и война","author":"Тацуки Фудзимото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008372355/140/3439/Tatsuki_Fudzimoto__Chelovekbenzopila._Kniga_7._Ptitsa_i_vojna.jpg","isbn":"978-5-389-22716-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2023","language":"Русский","series":"Графические романы. Манга","genres":["Комиксы","манга","графические романы"],"annotation":"Аса Митака — одинокая и молчаливая школьница, которая испытывает трудности в общении со своими одноклассниками. Ее жизнь ничем не примечательна. Но Аса даже не подозревает, что у нее есть враг, желающий ей смерти... Однажды ночью Аса оказывается лицом к лицу со своим недоброжелателем — и даже опомниться не успевает, как он ее убивает. Однако буквально за мгновение до смерти перед Асой появляется загадочное создание, которое предлагает девушке сделку. Все, что ей нужно, чтобы жить дальше, так это позволить незнакомцу вселиться в ее тело. Аса даже представить себе не могла, что, согласившись, накрепко связала свою жизнь с сильным демоном, преследующим единственную цель — победить Человека-Бензопилу... В книгу вошли главы 98–103.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2023-01","rating":4,"review":"","added":9999927,"hdCover":""},{"id":"0989636","title":"Человек-бензопила. Книга 6. Вперед, Человек-бензопила!","author":"Тацуки Фудзимото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007488204/140/1b97/Tatsuki_Fudzimoto__Chelovekbenzopila._Kniga_6._Vpered_Chelovekbenzopila.jpg","isbn":"978-5-389-21674-7","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"Фэнтези-ужасы для подростков","genres":["Комиксы","манга","графические романы"],"annotation":"Дэндзи превращается в Человека-Бензопилу и вступает в ожесточенную схватку с демоном-завоеванием и ее приспешниками, олицетворяющими различное оружие. Но каким бы сильным ни был Дэндзи, его противники отступать не намерены: они пойдут на все, лишь бы одержать верх над юношей. Это будет битва до последней капли крови, где малейшая ошибка может привести к смерти. Сможет ли Человек-Бензопила одолеть своих врагов? Или же рев его мотора заглохнет навсегда?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2023-01","rating":4.5,"review":"","added":9999926,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989635","title":"Человек-бензопила. Книга 5. Купание в ванне. Чувства собаки","author":"Тацуки Фудзимото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007440588/140/5c08/Tatsuki_Fudzimoto__Chelovekbenzopila._Kniga_5._Kupanie_v_vanne._Chuvstva_sobaki.jpg","isbn":"978-5-389-21430-9","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В жизни сотрудников специального четвертого отдела наступает затишье: Дэндзи, Пауэр и Аки Хаякава восстанавливают силы после тяжелой битвы с наемными убийцами и Санта-Клаусом. И за это время Аки еще сильнее сближается со своими взбалмошными коллегами... Однако на горизонте уже маячит новая миссия — масштабная операция по уничтожению демона — огнестрельное оружие, на которую Бюро общественной безопасности собирается бросить свои лучшие силы. Грядет невиданное ранее сражение, Дэндзи рвется в бой, а вот Хаякава, который больше других охотников мечтал убить демона-огнестрела, неожиданно понимает, что в жизни есть нечто более важное, чем месть...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2023-01","rating":5,"review":"","added":9999925,"hdCover":""},{"id":"0989634","title":"Человек-бензопила. Книга 4. Во сне. Настоящая жесть","author":"Тацуки Фудзимото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007280463/140/3d25/Tatsuki_Fudzimoto__Chelovekbenzopila._Kniga_4._Vo_sne._Nastoyaschaya_zhest.jpg","isbn":"978-5-389-21080-6","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"После ожесточенной схватки с Рэдзэ в жизни Дэндзи происходит внезапный поворот: юноша попадает в центр внимания СМИ. Практически все новостные каналы трубят об ужасающем демоне-бензопиле, объявившемся в Токио. Макима высказывает предположение, что теперь лидеры остальных стран во что бы то ни стало захотят заполучить такое редкое существо,как Дэндзи.Интуиция не обманывает главу спецотдела: в Японию начинают стягиваться лучшие наемники со всего света... И у каждого из них заключен договор с опаснейшим демоном.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2023-01","rating":4.5,"review":"Предыдущее прочтение: Апрель 2022, оценка 4.5","added":9999924,"hdCover":""},{"id":"0989633","title":"Клинок бессмертного. Книга 12","author":"Хироаки Самура","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007665762/140/fde8/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_12.jpg","isbn":"978-5-907576-11-7","publisher":"Alt Graph","pubDate":"2022","language":"Русский","series":"","genres":[],"annotation":"Итторю пора покинуть Эдо, но перед этим Аноцу Кагэхиса решает оставить прощальное послание сёгунату, которое запомнят надолго. Помогать ему в этом будет тройка верных товарищей и искуснейших воинов. Тем временем безжалостный маньяк Сира вновь оказывается на свободе, а его жажда крови становится лишь сильнее. Наконец-то он исполнит давнюю мечту и сойдется с Мандзи в решающей схватке. Правда, на этот раз предсказать ее исход будет не так просто: Мандзи хоть и бессмертный, но сражаться в полную силу без правой руки у него не получится, а Сира припас неожиданный козырь. У него было достаточно времени, чтобы продумать свой коварный план до мелочей, поэтому никто не гарантирует, что Мандзи сможет спастись сам и спасти Рин. Грядет одна из самых бескомпромиссных битв!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2023-01","rating":5,"review":"","added":9999923,"hdCover":""},{"id":"0989632","title":"Клинок бессмертного. Книга 11","author":"Хироаки Самура","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007665759/140/3cf7/Hiroaki_Samura__Klinok_bessmertnogo._Kniga_11.jpg","isbn":"978-5-907576-06-3","publisher":"Alt Graph","pubDate":"2022","language":"Русский","series":"","genres":[],"annotation":"Пленники замка Эдо наконец на свободе, а Хабаки Кагимура лишился всех постов и обязан сделать харакири. Правда, ему дана отсрочка на месяц, чтобы он мог завершить оставшиеся дела и все-таки расправиться с Итторю. Набрав банду отчаянных головорезов и смертников, именуемую Шестеркой демонов, он выходит на охоту. В это время новый комендант замка Эдо ведет свою хитроумную игру и начинает переговоры с Аноцу Кагэхисой за спиной Хабаки. После короткой передышки Мандзи и Рин вновь отправляются вслед за Аноцу, ведь теперь их судьбы тесно сплелись друг с другом.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2023-01","rating":5,"review":"","added":9999922,"hdCover":""},{"id":"0989631","title":"Batman: Year Two 30th Anniversary Deluxe Edition","author":"Mike W Barr","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470897/140/f31f/Mike_W_Barr__Batman_Year_Two_30th_Anniversary_Deluxe_Edition.jpg","isbn":"978-1401274566","publisher":"DC","pubDate":"2017","language":"","series":"","genres":[],"annotation":"Celebrating 30 years comes this amazing collection of classic Mike Barr comics from his iconic Batman series, BATMAN: YEAR TWO 30th ANNIVERSARY DELUXE EDITION.  A close friend of Bruce Wayne introduces him to Rachel Caspian, and the two quickly develop a romantic relationship. In the midst of love however, Rachel''s father decides to come out of retirment as the Reaper, Gotham''s first vigilante!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-11","rating":3,"review":"","added":9999921,"hdCover":""},{"id":"0989630","title":"Бэтмен. Убийственная шутка","author":"Алан Мур,Брайан Болланд,Джон Хиггинс,Марк Уэйд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002759258/140/fe67/__Betmen._Ubijstvennaya_shutka.jpg","isbn":"978-5-389-10977-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"«Чтобы превратить самого здравого человека на свете в полного психа, нужен всего один плохой день», — утверждает Джокер. Он снова сбежал из лечебницы Аркхем — лишь для того, чтобы доказать этот тезис. А помочь ему должны, сами того не желая, комиссар полиции Джим Гордон и его красавица-дочь Барбара.  Теперь лишь Бэтмен может спасти двух своих ближайших друзей от угрожающей им смертельной опасности. Под силу ли ему разорвать порочный круг безумия и кровавого насилия, навечно связавший его с Джокером, прежде чем наступит неизбежный, казалось бы, финал? И когда тайна происхождения короля преступного мира будет наконец раскрыта, не лопнет ли тонкая граница, отделяющая Бэтмена с его безупречным благородством от Джокера с его добровольным делирием?  В таких своих легендарных работах, как «Хранители» и «V — значит Vендетта», современный классик Алан Мур переписал правила супергеройского жанра. «Бэтмен: Убийственная шутка» — это его попытка по новой ответить на вечный вопрос о зарождении величайшего суперзлодея. попытка, после которой вселенная Бэтмена никогда не останется прежней.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Перечитал","read":"2022-11","rating":4,"review":"Предыдущее прочтение: 2017, оценка 4","added":9999920,"hdCover":""}]');
